    },
    {
      "role": "user",
      "content": "Extract a structured task from this voice note transcript:\n\n{{ $json.transcript }}"
    }
  ],
  "max_tokens": 500,
  "temperature": 0.3
}

parameters.jsCode:
let taskData;
try {
  const content = $json.choices[0].message.content;
  taskData = JSON.parse(content);
} catch (e) {
  taskData = {
    title: 'Voice Task — ' + new Date().toLocaleDateString(),
    description: 'Manually review this voice note. Auto-extraction failed.',
    priority: 'Medium',
    due_date: null,
    tags: ['voice-note', 'review-needed'],
    project: 'General',
    estimated_time: null
  };
}

const prev = $('Parse Transcript').item.json;

return [
  {
    json: {
      title: taskData.title || 'Untitled Task',
      description: taskData.description || '',
      priority: taskData.priority || 'Medium',
      due_date: taskData.due_date || null,
      tags: Array.isArray(taskData.tags) ? taskData.tags : ['voice-note'],
      project: taskData.project || 'General',
      estimated_time: taskData.estimated_time || null,
      transcript: prev.transcript,
      chat_id: prev.chat_id,
      user_name: prev.user_name,
      message_id: prev.message_id,
      duration: prev.duration,
      notion_token: prev.notion_token,
      notion_database_id: prev.notion_database_id,
      telegram_token: prev.telegram_token,
      timestamp: prev.timestamp,
      source: 'Telegram Voice'
    }
  }
];

